void create_matrix(float *m, int size) {
    int i, j;
    float lamda = -0.01f;
    float *coe = (float *)malloc((2 * size - 1) * sizeof(float));
    float coe_i = 0.0f;

    for (i = 0; i < size; i++) {
        coe_i = 10.0f * expf(lamda * i);
        j = size - 1 + i;
        coe[j] = coe_i;
        j = size - 1 - i;
        coe[j] = coe_i;
    }

    for (i = 0; i < size; i++) {
        for (j = 0; j < size; j++) {
            m[i * size + j] = coe[size - 1 - i + j];
        }
    }

    free(coe);
}

int main(int argc, char *argv[]) {
    printf("WG size of kernel 1 = %d, WG size of kernel 2= %d X %d\n", BLOCK_SIZE_0, BLOCK_SIZE_1_X, BLOCK_SIZE_1_Y);

    float *a = NULL, *b = NULL, *finalVec = NULL;
    float *m = NULL;
    int size = -1;

    FILE *fp;
    char filename[200] = {0};
    int show_data = 0, quiet = 0, timing = 0, platform = 0, device = 0;

    if (parseCommandline(argc, argv, filename, &quiet, &show_data, &timing, &platform, &device, &size)) {
        printUsage();
        return 0;
    }

#ifdef TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

    checkCuda(cudaSetDevice(device), "cudaSetDevice");

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    tvsub(&tv_init_end, &tv_total_start, &tv);
    init_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

    if (size < 1) {
        fp = fopen(filename, "r");
        if (!fp) {
            fprintf(stderr, "Error opening file %s\n", filename);
            return 1;
        }

        fscanf(fp, "%d", &size);

        a = (float *)malloc(size * size * sizeof(float));
        InitMat(fp, size, a, size, size);

        b = (float *)malloc(size * sizeof(float));
        InitAry(fp, b, size);

        fclose(fp);
    } else {
        printf("create input internally before create, size = %d \n", size);

        a = (float *)malloc(size * size * sizeof(float));
        create_matrix(a, size);

        b = (float *)malloc(size * sizeof(float));
        for (int i = 0; i < size; i++) b[i] = 1.0f;
    }

    if (!quiet && show_data) {
        printf("The input matrix a is:\n");
        PrintMat(a, size, size, size);

        printf("The input array b is:\n");
        PrintAry(b, size);
    }

    m = (float *)malloc(size * size * sizeof(float));
    finalVec = (float *)malloc(size * sizeof(float));

    InitPerRun(size, m);

    ForwardSub(NULL, a, b, m, size, timing);

    if (!quiet && show_data) {
        printf("The result of matrix m is: \n");
        PrintMat(m, size, size, size);
        printf("The result of matrix a is: \n");
        PrintMat(a, size, size, size);
        printf("The result of array b is: \n");
        PrintAry(b, size);

        BackSub(a, b, finalVec, size);
        printf("The final solution is: \n");
        PrintAry(finalVec, size);
    }

    free(m);
    free(a);
    free(b);
    free(finalVec);

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif

    checkCuda(cudaDeviceReset(), "cudaDeviceReset");

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
    tvsub(&tv_close_end, &tv_total_start, &tv);
    total_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;

    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif

    return 0;
}

void ForwardSub(void *context, float *a, float *b, float *m, int size, int timing) {
    (void)context;
    (void)timing;

    float *a_dev = NULL, *b_dev = NULL, *m_dev = NULL;
    float writeMB = 0, readMB = 0;

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif
    checkCuda(cudaMalloc((void **)&a_dev, sizeof(float) * size * size), "cudaMalloc a_dev");
    checkCuda(cudaMalloc((void **)&b_dev, sizeof(float) * size), "cudaMalloc b_dev");
    checkCuda(cudaMalloc((void **)&m_dev, sizeof(float) * size * size), "cudaMalloc m_dev");
#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

#ifdef TIMING
    cudaEvent_t e0, e1;
    checkCuda(cudaEventCreate(&e0), "cudaEventCreate");
    checkCuda(cudaEventCreate(&e1), "cudaEventCreate");
    float ms = 0.0f;
#endif

#ifdef TIMING
    checkCuda(cudaEventRecord(e0), "cudaEventRecord");
#endif
    checkCuda(cudaMemcpy(a_dev, a, sizeof(float) * size * size, cudaMemcpyHostToDevice), "cudaMemcpy a H2D");
#ifdef TIMING
    checkCuda(cudaEventRecord(e1), "cudaEventRecord");
    checkCuda(cudaEventSynchronize(e1), "cudaEventSynchronize");
    checkCuda(cudaEventElapsedTime(&ms, e0, e1), "cudaEventElapsedTime");
    h2d_time += ms;
#endif

#ifdef TIMING
    checkCuda(cudaEventRecord(e0), "cudaEventRecord");
#endif
    checkCuda(cudaMemcpy(b_dev, b, sizeof(float) * size, cudaMemcpyHostToDevice), "cudaMemcpy b H2D");
#ifdef TIMING
    checkCuda(cudaEventRecord(e1), "cudaEventRecord");
    checkCuda(cudaEventSynchronize(e1), "cudaEventSynchronize");
    checkCuda(cudaEventElapsedTime(&ms, e0, e1), "cudaEventElapsedTime");
    h2d_time += ms;
#endif

#ifdef TIMING
    checkCuda(cudaEventRecord(e0), "cudaEventRecord");
#endif
    checkCuda(cudaMemcpy(m_dev, m, sizeof(float) * size * size, cudaMemcpyHostToDevice), "cudaMemcpy m H2D");
#ifdef TIMING
    checkCuda(cudaEventRecord(e1), "cudaEventRecord");
    checkCuda(cudaEventSynchronize(e1), "cudaEventSynchronize");
    checkCuda(cudaEventElapsedTime(&ms, e0, e1), "cudaEventElapsedTime");
    h2d_time += ms;
#endif

    writeMB = (float)(sizeof(float) * size * (size + size + 1) / 1e6);

    int block1 = (BLOCK_SIZE_0 > 0) ? BLOCK_SIZE_0 : 256;
    int bx = (BLOCK_SIZE_1_X > 0) ? BLOCK_SIZE_1_X : 16;
    int by = (BLOCK_SIZE_1_Y > 0) ? BLOCK_SIZE_1_Y : 16;

    dim3 blockFan1(block1, 1, 1);
    dim3 gridFan1((size + block1 - 1) / block1, 1, 1);

    dim3 blockFan2(bx, by, 1);
    dim3 gridFan2((size + bx - 1) / bx, (size + by - 1) / by, 1);

    for (int t = 0; t < (size - 1); t++) {
#ifdef TIMING
        checkCuda(cudaEventRecord(e0), "cudaEventRecord");
#endif
        Fan1<<<gridFan1, blockFan1>>>(m_dev, a_dev, b_dev, size, t);
        checkCuda(cudaGetLastError(), "Fan1 launch");
        checkCuda(cudaDeviceSynchronize(), "Fan1 sync");
#ifdef TIMING
        checkCuda(cudaEventRecord(e1), "cudaEventRecord");
        checkCuda(cudaEventSynchronize(e1), "cudaEventSynchronize");
        checkCuda(cudaEventElapsedTime(&ms, e0, e1), "cudaEventElapsedTime");
        kernel_time += ms;
#endif

#ifdef TIMING
        checkCuda(cudaEventRecord(e0), "cudaEventRecord");
#endif
        Fan2<<<gridFan2, blockFan2>>>(m_dev, a_dev, b_dev, size, t);
        checkCuda(cudaGetLastError(), "Fan2 launch");
        checkCuda(cudaDeviceSynchronize(), "Fan2 sync");
#ifdef TIMING
        checkCuda(cudaEventRecord(e1), "cudaEventRecord");
        checkCuda(cudaEventSynchronize(e1), "cudaEventSynchronize");
        checkCuda(cudaEventElapsedTime(&ms, e0, e1), "cudaEventElapsedTime");
        kernel_time += ms;
#endif
    }

#ifdef TIMING
    checkCuda(cudaEventRecord(e0), "cudaEventRecord");
#endif
    checkCuda(cudaMemcpy(a, a_dev, sizeof(float) * size * size, cudaMemcpyDeviceToHost), "cudaMemcpy a D2H");
#ifdef TIMING
    checkCuda(cudaEventRecord(e1), "cudaEventRecord");
    checkCuda(cudaEventSynchronize(e1), "cudaEventSynchronize");
    checkCuda(cudaEventElapsedTime(&ms, e0, e1), "cudaEventElapsedTime");
    d2h_time += ms;
#endif

#ifdef TIMING
    checkCuda(cudaEventRecord(e0), "cudaEventRecord");
#endif
    checkCuda(cudaMemcpy(b, b_dev, sizeof(float) * size, cudaMemcpyDeviceToHost), "cudaMemcpy b D2H");
#ifdef TIMING
    checkCuda(cudaEventRecord(e1), "cudaEventRecord");
    checkCuda(cudaEventSynchronize(e1), "cudaEventSynchronize");
    checkCuda(cudaEventElapsedTime(&ms, e0, e1), "cudaEventElapsedTime");
    d2h_time += ms;
#endif

#ifdef TIMING
    checkCuda(cudaEventRecord(e0), "cudaEventRecord");
#endif
    checkCuda(cudaMemcpy(m, m_dev, sizeof(float) * size * size, cudaMemcpyDeviceToHost), "cudaMemcpy m D2H");
#ifdef TIMING
    checkCuda(cudaEventRecord(e1), "cudaEventRecord");
    checkCuda(cudaEventSynchronize(e1), "cudaEventSynchronize");
    checkCuda(cudaEventElapsedTime(&ms, e0, e1), "cudaEventElapsedTime");
    d2h_time += ms;
#endif

    readMB = (float)(sizeof(float) * size * (size + size + 1) / 1e6);

#ifdef TIMING
    printf("Matrix Size\tWrite(s) [size]\t\tKernel(s)\tRead(s)  [size]\t\tTotal(s)\n");
    printf("%dx%d      \t", size, size);
    printf("%f [%.2fMB]\t", h2d_time, writeMB);
    printf("%f\t", kernel_time);
    printf("%f [%.2fMB]\t", d2h_time, readMB);
    printf("%f\n\n", h2d_time + kernel_time + d2h_time);
#endif

#ifdef TIMING
    gettimeofday(&tv_close_start, NULL);
#endif
    checkCuda(cudaFree(a_dev), "cudaFree a_dev");
    checkCuda(cudaFree(b_dev), "cudaFree b_dev");
    checkCuda(cudaFree(m_dev), "cudaFree m_dev");
#ifdef TIMING
    checkCuda(cudaEventDestroy(e0), "cudaEventDestroy");
    checkCuda(cudaEventDestroy(e1), "cudaEventDestroy");
    gettimeofday(&tv_close_end, NULL);
    tvsub(&tv_close_end, &tv_close_start, &tv);
    close_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif
}

int parseCommandline(int argc, char *argv[], char *filename, int *q, int *v, int *t, int *p, int *d, int *size) {
    int i;
    if (argc < 2) return 1;
    char flag;

    for (i = 1; i < argc; i++) {
        if (argv[i][0] == '-') {
            flag = argv[i][1];
            switch (flag) {
                case 's':
                    i++;
                    *size = atoi(argv[i]);
                    printf("Create matrix internally in parse, size = %d \n", *size);
                    break;
                case 'f':
                    i++;
                    strncpy(filename, argv[i], 100);
                    filename[199] = '\0';
                    printf("Read file from %s \n", filename);
                    break;
                case 'h':
                    return 1;
                case 'q':
                    *q = 1;
                    break;
                case 'v':
                    *v = 1;
                    break;
                case 't':
                    *t = 1;
                    break;
                case 'p':
                    i++;
                    *p = atoi(argv[i]);
                    break;
                case 'd':
                    i++;
                    *d = atoi(argv[i]);
                    break;
            }
        }
    }
    if ((*d >= 0 && *p < 0) || (*p >= 0 && *d < 0)) return 1;
    return 0;
}

